function pascalTriangle(rows) {
  const triangle = [[1]];
  for (let i = 1; i < rows; i++) {
    const prev = triangle[i - 1];
    const row = [1];
    for (let j = 1; j < i; j++) {
      row[j] = prev[j - 1] + prev[j];
    }
    row[i] = 1;
    triangle.push(row);
  }
  return triangle;
}

function pascalRow(n) {
  if (n === 0) return [1];
  const prev = pascalRow(n - 1);
  return [1, ...prev.slice(0, -1).map((v, i) => v + prev[i + 1]), 1];
}

function pascalRowBinomial(n) {
  return Array.from({ length: n + 1 }, (_, i) =>
    factorialBigInt(n) / (factorialBigInt(i) * factorialBigInt(n - i))
  );
}
